SELECT expected_output
FROM date_calculations
WHERE test_case = 0;

SELECT input_date
FROM date_calculations
WHERE calculation_id = 0;

SELECT version_number
FROM version_control
ORDER BY timestamp DESC;

SELECT calculation_id, success_count, failure_count
FROM calculation_statistics
ORDER BY failure_count DESC;

SELECT user_id, COUNT(log_id) AS total_calculations
FROM calculation_logs
GROUP BY user_id;

SELECT COUNT(*) AS successful_calculations
FROM calculation_statistics
WHERE success_count > 0;

SELECT COUNT(*) AS total_logs
FROM calculation_logs
WHERE user_id = 0;

SELECT result
FROM calculation_logs
WHERE log_id = 1;

SELECT calculation_id, last_calculation, AVG(success_count * 1.0 / (success_count + failure_count)) AS success_rate
FROM calculation_statistics
GROUP BY calculation_id, last_calculation;
